        .when()
            .post(queuePath)
        .then()
            .statusCode(200)
            .body(containsString("QueueArn"));

        // Clean up
        given()
            .contentType("application/x-www-form-urlencoded")
            .formParam("Action", "DeleteQueue")
            .formParam("QueueUrl", testQueueUrl)
        .when()
            .post("/");
    }
}

