                    new AwsErrorResponse(e.jsonType(), e.getMessage()));
            return Response.status(e.getHttpStatus())
                    .header(protocolHeader, "rpc-v2-cbor")
                    .type("application/cbor")
                    .entity(errBytes)
                    .build();
        } catch (Exception ex) {
            return Response.status(e.getHttpStatus()).build();
        }
    }
}
